mapper.select:
SELECT DATE_FORMAT(record_time, '%Y-%m') as month, COALESCE(SUM(CASE WHEN points_change > 0 THEN points_change ELSE 0 END), 0) as earned, COALESCE(SUM(CASE WHEN points_change < 0 THEN ABS(points_change) ELSE 0 END), 0) as used FROM points_record
AND record_time >= #{startTime}
AND record_time <= #{endTime}
GROUP BY DATE_FORMAT(record_time, '%Y-%m') ORDER BY month ASC
